import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { io, Socket } from 'socket.io-client';
import { environment } from '../../../environments/environment';

@Injectable({
  providedIn: 'root',
})
export class WebsocketService {
  private socket?: Socket;

  private ensureConnection() {
    if (this.socket) {
      return this.socket;
    }

    this.socket = io(environment.wsUrl, {
      transports: ['websocket'],
    });

    return this.socket;
  }

  dashboardUpdates(): Observable<{ event: string; timestamp: string }> {
    return new Observable((subscriber) => {
      const socket = this.ensureConnection();
      const handler = (payload: { event: string; timestamp: string }) => subscriber.next(payload);

      socket.on('dashboard-update', handler);

      return () => {
        socket.off('dashboard-update', handler);
      };
    });
  }
}
