import { HttpClient } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import { ResourceSummary } from '../models/dashboard.models';

@Injectable({
  providedIn: 'root',
})
export class ResourcesService {
  private readonly http = inject(HttpClient);

  getResources(): Observable<ResourceSummary[]> {
    return this.http.get<ResourceSummary[]>(`${environment.apiUrl}/resources`);
  }

  getHistory(resourceId: number) {
    return this.http.get(`${environment.apiUrl}/resources/${resourceId}/history`);
  }
}
