import { HttpClient } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import { OptimizerResponse, OptimizerWeights } from '../models/dashboard.models';

@Injectable({
  providedIn: 'root',
})
export class OptimizerService {
  private readonly http = inject(HttpClient);

  rebalance(weights: OptimizerWeights): Observable<OptimizerResponse> {
    return this.http.post<OptimizerResponse>(`${environment.apiUrl}/optimizer/rebalance`, weights);
  }

  apply(weights: OptimizerWeights): Observable<OptimizerResponse> {
    return this.http.post<OptimizerResponse>(`${environment.apiUrl}/optimizer/apply`, weights);
  }

  simulate(weights: OptimizerWeights): Observable<OptimizerResponse> {
    return this.http.post<OptimizerResponse>(`${environment.apiUrl}/optimizer/simulate`, weights);
  }
}
