import { HttpClient } from '@angular/common/http';
import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import {
  HeatmapResponse,
  PerformanceResponse,
  SummaryResponse,
} from '../models/dashboard.models';

@Injectable({
  providedIn: 'root',
})
export class AnalyticsService {
  private readonly http = inject(HttpClient);

  getHeatmap(): Observable<HeatmapResponse> {
    return this.http.get<HeatmapResponse>(`${environment.apiUrl}/analytics/workload-heatmap`);
  }

  getSummary(): Observable<SummaryResponse> {
    return this.http.get<SummaryResponse>(`${environment.apiUrl}/analytics/summary`);
  }

  getPerformance(): Observable<PerformanceResponse> {
    return this.http.get<PerformanceResponse>(`${environment.apiUrl}/analytics/performance`);
  }
}
